@typeparam TItem
@implements IAsyncDisposable
@inject IJSRuntime JS

<div class="infinite-scroll-container">
    @foreach (var item in Items)
    {
        @ChildContent(item)
    }

    @if (HasMore)
    {
        <div @ref="_sentinelRef" class="infinite-scroll-sentinel">
            @if (_isLoading)
            {
                <div class="infinite-scroll-spinner" role="status">
                    <span>Loading...</span>
                </div>
            }
        </div>
    }
</div>

@code {
    private ElementReference _sentinelRef;
    private IJSObjectReference? _module;
    private IJSObjectReference? _observer;
    private DotNetObjectReference<InfiniteScrollList<TItem>>? _dotNetRef;
    private bool _isLoading;
    private CancellationTokenSource? _cts;

    [Parameter, EditorRequired]
    public IReadOnlyList<TItem> Items { get; set; } = [];

    [Parameter, EditorRequired]
    public bool HasMore { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnLoadMore { get; set; }

    [Parameter, EditorRequired]
    public RenderFragment<TItem> ChildContent { get; set; } = default!;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _dotNetRef = DotNetObjectReference.Create(this);
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./_content/sv_46c979e2842f4a5ab7e25b0bddff9652/Components/InfiniteScrollList.razor.js");
            await SetupObserver();
        }
    }

    protected override async Task OnParametersSetAsync()
    {
        // Re-observe when HasMore changes back to true after being false
        if (_module is not null && HasMore && _observer is null)
        {
            await SetupObserver();
        }
    }

    private async Task SetupObserver()
    {
        if (_module is null || !HasMore) return;

        await DisposeObserverAsync();
        _observer = await _module.InvokeAsync<IJSObjectReference>(
            "createObserver", _sentinelRef, _dotNetRef);
    }

    [JSInvokable]
    public async Task OnSentinelVisible()
    {
        if (_isLoading || !HasMore) return;

        _isLoading = true;
        StateHasChanged();

        _cts?.Cancel();
        _cts = new CancellationTokenSource();

        try
        {
            await OnLoadMore.InvokeAsync();
        }
        finally
        {
            _isLoading = false;
            StateHasChanged();
        }
    }

    private async ValueTask DisposeObserverAsync()
    {
        if (_observer is not null)
        {
            await _observer.InvokeVoidAsync("disconnect");
            await _observer.DisposeAsync();
            _observer = null;
        }
    }

    public async ValueTask DisposeAsync()
    {
        _cts?.Cancel();
        _cts?.Dispose();

        try
        {
            await DisposeObserverAsync();

            if (_module is not null)
            {
                await _module.DisposeAsync();
            }
        }
        catch (JSDisconnectedException)
        {
            // Circuit may already be gone
        }

        _dotNetRef?.Dispose();
    }
}

export function createObserver(sentinel, dotNetRef) {
    const observer = new IntersectionObserver(
        (entries) => {
            if (entries[0].isIntersecting) {
                dotNetRef.invokeMethodAsync('OnSentinelVisible');
            }
        },
        { rootMargin: '0px 0px 200px 0px' }
    );

    observer.observe(sentinel);
    return observer;
}

.infinite-scroll-container {
    overflow-y: auto;
}

.infinite-scroll-sentinel {
    display: flex;
    justify-content: center;
    padding: 1rem;
    min-height: 1px;
}

.infinite-scroll-spinner {
    width: 2rem;
    height: 2rem;
    border: 3px solid rgba(0, 0, 0, 0.1);
    border-top-color: #666;
    border-radius: 50%;
    animation: spin 0.8s linear infinite;
}

.infinite-scroll-spinner span {
    position: absolute;
    width: 1px;
    height: 1px;
    overflow: hidden;
    clip: rect(0, 0, 0, 0);
    white-space: nowrap;
}

@keyframes spin {
    to { transform: rotate(360deg); }
}

