        (entries) => {
            if (entries[0].isIntersecting) {
                dotNetRef.invokeMethodAsync('OnSentinelVisible');
            }
        },
        { rootMargin: '0px 0px 200px 0px' }
    );

    observer.observe(sentinel);
    return observer;
}

